from flask import Flask, request, jsonify
import logging
from logging.handlers import RotatingFileHandler
import json

app = Flask(__name__)

# Configure logging
handler = RotatingFileHandler('app.log', maxBytes=1000000, backupCount=10)
logging.basicConfig(level=logging.INFO, handlers=[handler], format='%(asctime)s - %(levelname)s - %(message)s')

@app.before_request
def log_request():
    logging.info('Request Headers: %s', request.headers)
    logging.info('Request Body: %s', request.get_data(as_text=True))

@app.after_request
def log_response(response):
    logging.info('Response Status: %s', response.status)
    logging.info('Response Body: %s', response.get_data(as_text=True))
    return response

@app.errorhandler(Exception)
def handle_error(error):
    logging.error('Error: %s', str(error))
    return jsonify({'error': 'Internal Server Error'}), 500

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    logging.info('Login attempt for user: %s', username)
    logging.info('Password: %s', password)
    
    if username == 'admin' and password == 'secret':  # Example check
        return jsonify({'message': 'Login successful'}), 200
    else:
        logging.warning('Failed login attempt for user: %s', username)
        return jsonify({'message': 'Invalid credentials'}), 401

if __name__ == '__main__':
    app.run(debug=True)